import { useEffect, useMemo, useState } from "react";
import { api, getAuthToken } from "../api";

export default function Cart() {
  const [items, setItems] = useState([]);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");

  const total = useMemo(
    () => items.reduce((sum, item) => sum + item.quantity * item.medicine_detail.price, 0),
    [items]
  );

  const loadCart = async () => {
    if (!getAuthToken()) {
      setError("Please login to view cart.");
      setItems([]);
      return;
    }
    try {
      setError("");
      const res = await api.get("/cart/");
      setItems(res.data);
    } catch (err) {
      setError("Unable to load cart.");
    }
  };

  useEffect(() => {
    loadCart();
  }, []);

  const updateQuantity = async (id, quantity) => {
    try {
      await api.patch(`/cart/${id}/`, { quantity: Number(quantity) });
      loadCart();
    } catch (err) {
      setError("Unable to update quantity.");
    }
  };

  const removeItem = async (id) => {
    try {
      await api.delete(`/cart/${id}/`);
      loadCart();
    } catch (err) {
      setError("Unable to remove item.");
    }
  };

  const placeOrder = async () => {
    try {
      setMessage("");
      setError("");
      if (!items.length) {
        setError("Your cart is empty.");
        return;
      }
      await api.post("/orders/", { items: items.map((i) => i.id) });
      for (const item of items) {
        await api.delete(`/cart/${item.id}/`);
      }
      setMessage("Order placed successfully.");
      loadCart();
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to place order.");
    }
  };

  return (
    <div className="page">
      <h2>Your Cart</h2>
      {error && <p>{error}</p>}
      {message && <p>{message}</p>}

      {items.map((item) => (
        <div className="card" key={item.id}>
          <h3>{item.medicine_detail.name}</h3>
          <p>Unit Price: Rs {item.medicine_detail.price}</p>
          <label>
            Quantity:
            <input
              type="number"
              min="1"
              value={item.quantity}
              onChange={(e) => updateQuantity(item.id, e.target.value)}
            />
          </label>
          <button onClick={() => removeItem(item.id)}>Remove</button>
        </div>
      ))}

      <h3>Total: Rs {total.toFixed(2)}</h3>
      <button onClick={placeOrder}>Place Order</button>
    </div>
  );
}
